def num_islands(grid):
    if not grid:
        return 0
    rows, cols = len(grid), len(grid[0])
    g = [row[:] for row in grid]
    count = 0
    for r in range(rows):
        for c in range(cols):
            if g[r][c] == "1":
                count += 1
                stack = [(r, c)]
                g[r][c] = "0"
                while stack:
                    cr, cc = stack.pop()
                    for dr, dc in ((1, 0), (-1, 0), (0, 1), (0, -1)):
                        nr, nc = cr + dr, cc + dc
                        if 0 <= nr < rows and 0 <= nc < cols and g[nr][nc] == "1":
                            g[nr][nc] = "0"
                            stack.append((nr, nc))
    return count
